<script>
  (function () {
    function startCreamassScrollbar() {
      var wrapper = document.getElementById('creamassTableWrapper');
      var thumb = document.getElementById('creamassScrollbarThumb');
      var bar = document.getElementById('creamassFakeScrollbar');

      if (!wrapper || !thumb || !bar) return;

      function updateScrollbar() {
        var maxScroll = wrapper.scrollWidth - wrapper.clientWidth;
        var barWidth = bar.clientWidth;

        if (maxScroll <= 0) {
          thumb.style.width = barWidth + 'px';
          thumb.style.left = '0px';
          return;
        }

        var thumbWidth = (wrapper.clientWidth / wrapper.scrollWidth) * barWidth;
        var maxThumbMove = barWidth - thumbWidth;
        var thumbLeft = (wrapper.scrollLeft / maxScroll) * maxThumbMove;

        thumb.style.width = thumbWidth + 'px';
        thumb.style.left = thumbLeft + 'px';
      }

      wrapper.addEventListener('scroll', updateScrollbar);
      window.addEventListener('resize', updateScrollbar);

      setTimeout(updateScrollbar, 100);
      setTimeout(updateScrollbar, 500);
      updateScrollbar();
    }

    if (document.readyState === 'loading') {
      document.addEventListener('DOMContentLoaded', startCreamassScrollbar);
    } else {
      startCreamassScrollbar();
    }

    document.addEventListener('shopify:section:load', startCreamassScrollbar);
  })();
</script>

